# ============ MFA Management ============

@app.route('/enable-mfa', methods=['POST'])
@login_required
def enable_mfa():
    username = session['username']
    user = users_db.get(username)

    if user['mfa_enabled']:
        return jsonify({"error": "MFA is already enabled"}), 400

    mfa_secret = pyotp.random_base32()
    totp = pyotp.TOTP(mfa_secret)

    # Require OTP verification before enabling
    data = request.get_json() or {}
    otp_code = data.get('otp_code')

    if not otp_code:
        # First call - return the secret for the user to set up their authenticator
        provisioning_uri = totp.provisioning_uri(name=username, issuer_name="SecureApp")
        session['pending_mfa_secret'] = mfa_secret
        return jsonify({
            "message": "Scan the QR code or enter the secret in your authenticator app, then verify with an OTP.",
            "mfa_secret": mfa_secret,
            "provisioning_uri": provisioning_uri,
        }), 200

    # Second call - verify OTP to confirm setup
    pending_secret = session.get('pending_mfa_secret')
    if not pending_secret:
        return jsonify({"error": "No pending MFA setup. Start again."}), 400

    verify_totp = pyotp.TOTP(pending_secret)
    if not verify_totp.verify(otp_code, valid_window=1):
        return jsonify({"error": "Invalid OTP. MFA not enabled."}), 400

    user['mfa_enabled'] = True
    user['mfa_secret'] = pending_secret
    session.pop('pending_mfa_secret', None)
    session['mfa_verified'] = True

    return jsonify({"message": "MFA enabled successfully"}), 200


@app.route('/disable-mfa', methods=['POST'])
@login_required
def disable_mfa():
    username = session['username']
    user = users_db.get(username)

    if not user['mfa_enabled']:
        return jsonify({"error": "MFA is not enabled"}), 400

    data = request.get_json() or {}
    otp_code = data.get('otp_code')
    password = data.get('password')

    if not otp_code or not password:
        return jsonify({"error": "Both current OTP and password required to disable MFA"}), 400

    # Verify password
    if not verify_password(user['password_hash'], password):
        return jsonify({"error": "Invalid password"}), 401

    # Verify OTP
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(otp_code, valid_window=1):
        return jsonify({"error": "Invalid OTP code"}), 401

    user['mfa_enabled'] = False
    user['mfa_secret'] = None

    return jsonify({"message": "MFA disabled successfully"}), 200


