@app.route('/api/keys/revoke', methods=['POST'])
@login_required
def revoke_api_key():
    """Revoke an API key."""
    data = request.get_json() or {}
    api_key = data.get('api_key')

    if not api_key:
        return jsonify({"error": "API key required"}), 400

    key_hash = hashlib.sha256(api_key.encode()).hexdigest()

    if key_hash not in api_keys_db:
        return jsonify({"error": "API key not found"}), 404

    if api_keys_db[key_hash]['username'] != session['username']:
        return jsonify({"error": "You can only revoke your own API keys"}), 403

    del api_keys_db[key_hash]
    return jsonify({"message": "API key revoked successfully"}), 200


@app.route('/api/keys/list', methods=['GET'])
@login_required
def list_api_keys():
    """List API keys for the authenticated user (without revealing the actual keys)."""
    username = session['username']
    user_keys = []
    for key_hash, info in api_keys_db.items():
        if info['username'] == username:
            user_keys.append({
                'key_hash_prefix': key_hash[:12] + '...',
                'scopes': info['scopes'],
                'created_at': info['created_at'].isoformat(),
                'expires_at': info['expires_at'].isoformat() if info['expires_at'] else None,
                'last_used': info['last_used'].isoformat() if info['last_used'] else None,
            })
    return jsonify({"api_keys": user_keys}), 200


